Rule.Source:
import sailpoint.tools.Util;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  Log logger = LogFactory.getLog("rule.Invision.Field.Values");

  logger.debug("Entering RACF-Invision Provisioning Policy Form Rule for Generating InvisionID field Value");
  
  String racfName = null;
  if(identity != null){
  String type = "";
  Boolean duplicate=false;
  String firstName = identity.getFirstname();
  String lastName = identity.getLastname();
  String middleName = identity.getAttribute("middleInitial");
  String filteredFname = filterSpecialCharacter(firstName);
  String filteredLname = filterSpecialCharacter(lastName);
  String filteredMname = filterSpecialCharacter(middleName);

  if (Util.isNotNullOrEmpty(filteredFname) && Util.isNotNullOrEmpty(filteredLname) && filteredLname.length() > 5){

    racfName = filteredFname.substring(0,1) + filteredLname.substring(0,5);
    duplicate = checkDuplicateInvisionID(racfName);
    if(duplicate){
      for(int i = 1; i < 10 ; i++){

        racfName = filteredFname.substring(0,1) + filteredLname.substring(0,4) + i;             
        duplicate = checkDuplicateInvisionID(racfName);
        if(duplicate){
          continue;
        }
        else{
          break;
        }      
      }
    }
  }
  else if (Util.isNotNullOrEmpty(filteredFname) && Util.isNotNullOrEmpty(filteredLname)){
    racfName = filteredFname.substring(0,1) + filteredLname;
    duplicate = checkDuplicateInvisionID(racfName);
    if(duplicate){
      for(int i = 1; i < 10 ; i++){

        racfName = filteredFname.substring(0,1) + filteredLname + i;             
        duplicate = checkDuplicateInvisionID(racfName);
        if(duplicate){
          continue;
        }
        else{
          break;
        }      
      }
    }
  }
  }
  logger.debug("Exiting RACF-Invision Provisioning Policy Form Rule for Generating InvisionID field Value");

  return racfName;
